// Map GitGuardian webhook payload to a Telegram-friendly Markdown message.
// Reference: https://docs.gitguardian.com/api-reference/webhooks/payload
// Works for both 'incident.created' and 'incident.resolved' event types.

const body = $input.first().json.body || $input.first().json;
const event = body.event || 'incident';
const incident = body.incident || body;
const secret = incident.secret_type || incident.detector?.display_name || 'unknown';
const severity = incident.severity || 'unknown';
const status = incident.status || 'triggered';
const source = incident.source?.full_name || incident.source?.name || incident.source_name || 'unknown';
const url = incident.incident_url || incident.gitguardian_url || 'https://dashboard.gitguardian.com/';

const emoji = status === 'resolved' ? '\u2705' : '\ud83d\udea8';
const title = status === 'resolved' ? 'Incident resolved' : 'GitGuardian incident';

const text = [
  emoji + ' *' + title + '*',
  'Secret: `' + secret + '`',
  'Severity: ' + severity,
  'Repo: `' + source + '`',
  'Event: `' + event + '`',
  '[Open in GitGuardian](' + url + ')'
].join('\n');

return [{ json: { text } }];
